import javax.swing.*;
public class BadUpdate {
    public static void main(String[] args) {
        JLabel label = new JLabel("waiting...");
        JFrame frame = new JFrame();
        frame.add(label);
        frame.setSize(200, 100);
        frame.setVisible(true);

        new Thread(() -> {
            for (int i = 1; i <= 5; i++) {
                label.setText("count: " + i);   // Swing is NOT thread-safe
                Thread.sleep(500);
            }
        }).start();
    }
}
